import {useEffect, useState} from "react";
import {Calendar} from "primereact/calendar";
import type {FormEvent} from "primereact/ts-helpers";
import type {EditorEl} from "../Editor";

const DateFilterTemplate: EditorEl<{

}> = (options) => {


  const value =
      !Array.isArray(options.value)
      ? null
      : options.value;

  const [selectedValue, setSelectedValue] = useState<any>(value);

  useEffect(() => {
    if (!Array.isArray(options.value)) {
      setSelectedValue(options.value);
    }
  }, [options.value]);

  // Function to adjust time for start and end of the day
  const adjustDateTime = (date: Date, isStart: boolean): Date => {
    if (!date) return date;
    const adjustedDate = new Date(date);
    if (isStart) {
      adjustedDate.setHours(0, 0, 0, 0); // Start of the day (00:00:00)
    } else {
      adjustedDate.setHours(23, 59, 59, 999); // End of the day (23:59:59)
    }
    return adjustedDate;
  };

  return (
    <Calendar
      id={"table-date-filter"}
      value={options.value ?? selectedValue}
      dateFormat="dd/mm/yy"
      placeholder={"dd/mm/yyyy - dd/mm/yyyy" }
      selectionMode={"range"}
      view={"date"}
      numberOfMonths={3}
      onChange={(event: FormEvent<any>) => {
        let adjustedValue = event.value;
        if (Array.isArray(adjustedValue) && adjustedValue.length === 2) {
          adjustedValue = [
            adjustDateTime(adjustedValue[0], true),  // Start of the first day
            adjustDateTime(adjustedValue[1], false), // End of the second day
          ];
        }

        options.editorCallback && options.editorCallback(adjustedValue);
        setSelectedValue(adjustedValue);
      }}
    />
  );
};

export default DateFilterTemplate;
